code_example_1.code:
/ Global Variable
Definition /
:root {
 --primary-color: #ff4757;
 --secondary-color:
#2f3542;
 --text-white: #ffffff;
 --padding-standard: 20px;
}

body {

background-color: var(--secondary-color);
 color: var(--text-white);
 padding:
var(--padding-standard);
}

.btn {
 background-color:
var(--primary-color);
 color: var(--text-white);
 padding: 10px
var(--padding-standard);
 border: none;
 border-radius: 5px;
 cursor:
pointer;
}

.btn:hover {
 / Brightening the primary color slightly on hover
/
 filter: brightness(1.2);
}

code_example_2.code:
/ BEM: Block (card)
/
.card {
 width: 300px;
 background: white;
 border: 1px solid #ddd;

overflow: hidden;
}

/ BEM: Element (image inside card) /
.card__image {

width: 100%;
 height: 200px;
 object-fit: cover;
 filter:
grayscale(50%);
}

/ BEM: Element (content area) /
.card__content {
 /
Using calc to ensure perfect padding regardless of border /
 padding: calc(10px
+ 1rem);
}

/ BEM: Modifier (special version of card) /
.card--featured {

border: 2px solid gold;
 transform: scale(1.05);
}

/ BEM: Element within a
Modifier /
.card--featured .card__content {
 background-color: #fff9e6;
}

